SELECT CL.COLLECT_LOG_ID, CL.SERVER_ID, CL.SERVER_IP, CL.SOURCE_FILE_PATH, CL.LOG_TYPE, CL.LOG_ID, CL.LOG_TIMESTAMP, CL.LOG_CONTENT, CL.LOG_VALUE, CL.RAW_LOG, CL.COLLECT_DATE, CL.COLLECT_DATETIME, CL.SCHEDULE_TYPE, CL.LINE_NUMBER, CL.CREATED_AT FROM TB_COLLECT_LOG CL
CL.COLLECT_DATE = #{collectDate} AND CL.SERVER_ID = #{serverId}
AND CL.SOURCE_FILE_PATH = #{sourceFilePath}
AND NOT EXISTS ( SELECT 1 FROM TB_ANALYZE_RESULT AR WHERE AR.COLLECT_LOG_ID = CL.COLLECT_LOG_ID )
ORDER BY CL.COLLECT_LOG_ID ASC

SELECT CL.COLLECT_LOG_ID, CL.SERVER_ID, CL.SERVER_IP, CL.SOURCE_FILE_PATH, CL.LOG_TYPE, CL.LOG_ID, CL.LOG_TIMESTAMP, CL.LOG_CONTENT, CL.LOG_VALUE, CL.RAW_LOG, CL.COLLECT_DATE, CL.COLLECT_DATETIME, CL.SCHEDULE_TYPE, CL.LINE_NUMBER, CL.CREATED_AT FROM TB_COLLECT_LOG CL
CL.COLLECT_DATE = #{collectDate} AND CL.SERVER_ID = #{serverId}
AND CL.SOURCE_FILE_PATH = #{sourceFilePath}
AND CL.COLLECT_LOG_ID > #{afterCollectLogId} AND NOT EXISTS ( SELECT 1 FROM TB_ANALYZE_RESULT AR WHERE AR.COLLECT_LOG_ID = CL.COLLECT_LOG_ID )
ORDER BY CL.COLLECT_LOG_ID ASC
